using System;
using System.Linq; // For LINQ Reverse() method

public class StringReversal
{
    public static void Main(string[] args)
    {
        string originalString = "C# Object Oriented";
        Console.WriteLine($"Original: {originalString}");

        // Method 1: Using char array (most common)
        char[] charArray = originalString.ToCharArray();
        Array.Reverse(charArray); // Reverses the array in place
        string reversedStringArray = new string(charArray);
        Console.WriteLine($"Reversed (char array): {reversedStringArray}");

        // Method 2: Using LINQ (creates new sequence)
        // Note: Reverse() returns IEnumerable<char>, needs joining.
        string reversedStringLinq = new string(originalString.Reverse().ToArray());
        Console.WriteLine($"Reversed (LINQ): {reversedStringLinq}");

        // Method 3: Manual loop (less common for this task in C#)
        var sb = new System.Text.StringBuilder(originalString.Length);
        for (int i = originalString.Length - 1; i >= 0; i--)
        {
            sb.Append(originalString[i]);
        }
        string reversedStringLoop = sb.ToString();
        Console.WriteLine($"Reversed (Loop): {reversedStringLoop}");

        // All these methods handle Unicode correctly in .NET strings.
    }
}

