using System;
using System.Collections.Generic;
using System.Numerics; // Required for BigInteger

public class FibonacciCalculator
{
    // Calculates the Nth Fibonacci number (0-indexed) using BigInteger
    public static BigInteger Fibonacci(int n)
    {
        if (n < 0) throw new ArgumentException("Input must be non-negative", nameof(n));
        if (n == 0) return BigInteger.Zero;
        if (n == 1) return BigInteger.One;

        BigInteger a = 0;
        BigInteger b = 1;

        for (int i = 2; i <= n; i++)
        {
            BigInteger temp = a + b;
            a = b;
            b = temp;
            // BigInteger handles overflow automatically
        }
        return b;
    }

    // Generates the first 'count' Fibonacci numbers
    public static List<BigInteger> GenerateFibonacciSequence(int count)
    {
        if (count < 0) throw new ArgumentException("Count must be non-negative", nameof(count));
        var sequence = new List<BigInteger>(count); // Pre-allocate capacity
        for (int i = 0; i < count; i++)
        {
            sequence.Add(Fibonacci(i));
        }
        return sequence;
    }

    public static void Main(string[] args)
    {
        int n = 10;
        Console.WriteLine($"Fibonacci number F({n}): {Fibonacci(n)}");

        int numTerms = 15;
        Console.WriteLine($"First {numTerms} Fibonacci numbers:");
        List<BigInteger> sequence = GenerateFibonacciSequence(numTerms);
        // Print the list (ToString on List<T> isn't always pretty)
        Console.WriteLine($"[{string.Join(", ", sequence)}]");

        // Example with large number
        int largeN = 90; // Well beyond Int64 limit
        Console.WriteLine($"Fibonacci number F({largeN}): {Fibonacci(largeN)}");
    }
}

