using System;
using System.Numerics; // Required for BigInteger

public class FactorialCalculator
{
    // Calculates factorial N! using BigInteger
    public static BigInteger Factorial(int n)
    {
        if (n < 0)
        {
            throw new ArgumentException("Factorial is not defined for negative numbers.", nameof(n));
        }

        BigInteger result = BigInteger.One; // Factorial of 0 is 1
        for (int i = 2; i <= n; i++) // Start from 2, as multiplying by 1 is redundant
        {
            result *= i;
        }
        return result;
    }

    public static void Main(string[] args)
    {
        int num = 5;
        Console.WriteLine($"Factorial of {num} is: {Factorial(num)}");

        num = 0;
        Console.WriteLine($"Factorial of {num} is: {Factorial(num)}");

        num = 20; // Max for Int64
        Console.WriteLine($"Factorial of {num} is: {Factorial(num)}");

        num = 30; // Requires BigInteger
        Console.WriteLine($"Factorial of {num} is: {Factorial(num)}");

        // Example invalid input
        try
        {
            Factorial(-3);
        }
        catch (ArgumentException ex)
        {
            Console.WriteLine($"Error calculating factorial: {ex.Message}");
        }
    }
}

