using System;

public class PrimeChecker
{
    // Checks if a number is prime
    public static bool IsPrime(long n) // Use long for larger range
    {
        if (n <= 1) return false;
        if (n <= 3) return true;
        if (n % 2 == 0 || n % 3 == 0) return false;

        // Check factors from 5 upwards, stepping by 6
        long limit = (long)Math.Sqrt(n);
        for (long i = 5; i <= limit; i += 6)
        {
            if (n % i == 0 || n % (i + 2) == 0)
            {
                return false; // Divisor found
            }
        }
        return true; // No divisors found
    }

    public static void Main(string[] args)
    {
        long[] numbersToCheck = { 2L, 3L, 4L, 17L, 25L, 29L, 97L, 100L, 1L, -5L, 1_000_000_007L };

        foreach (long n in numbersToCheck)
        {
            if (IsPrime(n))
            {
                Console.WriteLine($"{n} is prime.");
            }
            else
            {
                Console.WriteLine($"{n} is not prime.");
            }
        }
    }
}

