using System;
using System.IO; // Required for File operations

public class FileReaderExample
{
    public static void Main(string[] args)
    {
        string filePath = "csharp_read_test.txt";

        // Create a dummy file for reading
        try
        {
            string[] linesToWrite = { "Line 1 content from C#.", "This is the second line.", "End." };
            File.WriteAllLines(filePath, linesToWrite);
            Console.WriteLine($"Created dummy file '{filePath}' for reading.");
        }
        catch (Exception ex)
        {
             Console.WriteLine($"Error creating dummy file: {ex.Message}");
             return; // Cannot proceed if file creation failed
        }


        Console.WriteLine($"--- Reading file '{filePath}' ---");
        if (File.Exists(filePath))
        {
            try
            {
                // Method 1: Read all text into one string
                Console.WriteLine("\\n--- Reading using ReadAllText ---");
                string fileContent = File.ReadAllText(filePath); // Reads entire file
                Console.WriteLine("File content as single string:");
                Console.WriteLine(fileContent);
                Console.WriteLine("--- End of ReadAllText ---");

                // Method 2: Read all lines into a string array
                Console.WriteLine("\\n--- Reading using ReadAllLines ---");
                string[] lines = File.ReadAllLines(filePath); // Reads lines into array
                Console.WriteLine($"Read {lines.Length} lines:");
                int lineNumber = 1;
                foreach (string line in lines)
                {
                    Console.WriteLine($"Line {lineNumber++}: {line}");
                }
                Console.WriteLine("--- End of ReadAllLines ---");
            }
            catch (IOException ex) // Catch specific IO errors
            {
                Console.WriteLine($"An error occurred while reading the file: {ex.Message}");
            }
            catch (Exception ex) // Catch other potential errors
            {
                Console.WriteLine($"An unexpected error occurred: {ex.Message}");
            }
            finally
            {
                 // Clean up dummy file
                 File.Delete(filePath);
                 Console.WriteLine($"\\nCleaned up dummy file '{filePath}'.");
            }
        }
        else
        {
            Console.WriteLine($"Error: File not found '{filePath}'");
            // Clean up attempt in case it exists despite File.Exists failing somehow
            if (File.Exists(filePath)) { File.Delete(filePath); }
        }
    }
}

