using System;
using System.Globalization; // For CultureInfo if needed

public class DateTimeExamples
{
    public static void Main(string[] args)
    {
        Console.WriteLine("--- Current Date and Time ---");
        DateTime now = DateTime.Now;       // Local time
        DateTime utcNow = DateTime.UtcNow; // UTC time

        Console.WriteLine($"Local DateTime Object: {now}");
        Console.WriteLine($"UTC DateTime Object: {utcNow}");

        // It's often best practice to work with UTC and convert to local only for display
        DateTimeOffset nowOffset = DateTimeOffset.Now; // Includes offset from UTC
        Console.WriteLine($"DateTimeOffset Object: {nowOffset}");


        Console.WriteLine("\\n--- Common Formats (.NET ToString) ---");
        // See: https://learn.microsoft.com/en-us/dotnet/standard/base-types/standard-date-and-time-format-strings
        Console.WriteLine($"Short Date (d): {now.ToString("d")}"); // Culture-specific
        Console.WriteLine($"Long Date (D): {now.ToString("D")}");  // Culture-specific
        Console.WriteLine($"Short Time (t): {now.ToString("t")}"); // Culture-specific
        Console.WriteLine($"Long Time (T): {now.ToString("T")}");  // Culture-specific
        Console.WriteLine($"Sortable (s): {now.ToString("s")}");   // ISO 8601 style YYYY-MM-DDTHH:mm:ss
        Console.WriteLine($"RFC1123 (R): {now.ToString("R")}");    // Standard internet format
        Console.WriteLine($"Universal Sortable (u): {utcNow.ToString("u")}"); // UTC sortable YYYY-MM-DD HH:mm:ssZ

        Console.WriteLine("\\n--- Custom Formats ---");
        Console.WriteLine($"YYYY-MM-DD: {now.ToString("yyyy-MM-dd")}");
        Console.WriteLine($"HH:mm:ss (24hr): {now.ToString("HH:mm:ss")}");
        Console.WriteLine($"Readable: {now.ToString("dddd, MMMM dd, yyyy 'at' hh:mm:ss tt", CultureInfo.InvariantCulture)}"); // Specify culture for consistency

        Console.WriteLine("\\n--- Components ---");
        Console.WriteLine($"Year: {now.Year}");
        Console.WriteLine($"Month: {now.Month}");
        Console.WriteLine($"Day: {now.Day}");
        Console.WriteLine($"Hour: {now.Hour}");
        Console.WriteLine($"Minute: {now.Minute}");
        Console.WriteLine($"Second: {now.Second}");
        Console.WriteLine($"Millisecond: {now.Millisecond}");
        Console.WriteLine($"DayOfWeek: {now.DayOfWeek}");
        Console.WriteLine($"DayOfYear: {now.DayOfYear}");

        Console.WriteLine("\\n--- Unix Epoch Seconds ---");
        // Calculate seconds since 1970-01-01 00:00:00Z
        long epochSeconds = nowOffset.toUnixTimeSeconds(); // Easiest way using DateTimeOffset
        // Alternative using DateTime:
        // TimeSpan timeSinceEpoch = utcNow - new DateTime(1970, 1, 1, 0, 0, 0, DateTimeKind.Utc);
        // long epochSecondsAlt = (long)timeSinceEpoch.TotalSeconds;
        Console.WriteLine($"Seconds since epoch (UTC): {epochSeconds}");
    }
}

