using System;
using System.Linq; // Required for LINQ extension methods like Max()
using System.Collections.Generic; // For List<T> example

public class MaxFinder
{
    public static void Main(string[] args)
    {
        // Example with integer array
        int[] numbers = { 10, 5, 42, 17, 8, 99, 32, -5, 0 };
        Console.WriteLine($"Array: [{string.Join(", ", numbers)}]");

        if (numbers == null || numbers.Length == 0)
        {
            Console.WriteLine("Array is null or empty, cannot find maximum.");
        }
        else
        {
            // Use LINQ's Max() extension method
            int maxValue = numbers.Max();
            Console.WriteLine($"Maximum value (LINQ): {maxValue}");
        }

        // Example with List<double>
        List<double> floatList = new List<double> { 1.5, -0.5, 3.14, 2.71, 3.14159 };
        Console.WriteLine($"\\nList: [{string.Join(", ", floatList)}]");

        if (floatList == null || !floatList.Any()) // .Any() is LINQ way to check if not empty
        {
             Console.WriteLine("List is null or empty.");
        }
        else
        {
            double maxFloat = floatList.Max();
            Console.WriteLine($"Maximum value (LINQ): {maxFloat}");
        }

        // Example with empty array/list
        int[] emptyArray = {};
        Console.WriteLine($"\\nArray: [{string.Join(", ", emptyArray)}]");
        try
        {
            // Max() throws InvalidOperationException on empty sequence
             int maxEmpty = emptyArray.Max();
             Console.WriteLine($"Maximum value (empty): {maxEmpty}"); // Won't reach here
        }
        catch (InvalidOperationException)
        {
            Console.WriteLine("Cannot find maximum value in an empty array.");
        }
    }
}
